insert into public.modelos_producto (codigo_modelo, nombre_modelo, nombre_normalizado, estado, metadata)
select codigo_modelo, nombre_modelo, nombre_normalizado, estado, metadata from fuente
on conflict (nombre_normalizado) do update
set codigo_modelo = excluded.codigo_modelo,
    nombre_modelo = excluded.nombre_modelo,
    estado = excluded.estado,
    metadata = excluded.metadata;

