insert into public.modelos_producto_variantes (modelo_id, codigo_modelo, codigo_variante, nombre_modelo, color, color_normalizado, talla, talla_normalizada, descripcion_variante, estado, metadata)
select
  m.id,
  m.codigo_modelo,
  f.codigo_variante,
  m.nombre_modelo,
  f.color,
  f.color_normalizado,
  f.talla,
  f.talla_normalizada,
  f.descripcion_variante,
  f.estado,
  f.metadata
from fuente f
join public.modelos_producto m on m.nombre_normalizado = f.nombre_normalizado
on conflict (modelo_id, color_normalizado, talla_normalizada) do update
set codigo_modelo = excluded.codigo_modelo,
    codigo_variante = excluded.codigo_variante,
    nombre_modelo = excluded.nombre_modelo,
    color = excluded.color,
    talla = excluded.talla,
    descripcion_variante = excluded.descripcion_variante,
    estado = excluded.estado,
    metadata = excluded.metadata;

insert into public.historial_versiones (version, fecha, titulo, detalle)
values (
  'Cynara v1.0.1', current_date, 'Carga maestra de modelos', 'Se importaron modelos y variantes unicas desde modelos.xlsx para unificar codigos de producto.'
);

commit;
